"use client";

import { memo, useCallback, useEffect, useId, useRef, useState } from "react";
import { cn } from "@/lib/utils";
import { ShareButton, type CopyState } from "./parts/share-button";
import { SHARE_TEMPLATES } from "./parts/templates";
import {
  SHARE_BAR_DEFAULT_LABELS,
  type ShareBar01Props,
  type ShareTarget,
} from "./types";

async function copyToClipboard(text: string): Promise<void> {
  if (typeof navigator !== "undefined" && navigator.clipboard?.writeText) {
    return navigator.clipboard.writeText(text);
  }
  if (typeof document === "undefined") {
    throw new Error("Clipboard not available (no document)");
  }
  const textarea = document.createElement("textarea");
  textarea.value = text;
  textarea.style.position = "fixed";
  textarea.style.opacity = "0";
  document.body.appendChild(textarea);
  textarea.select();
  try {
    if (!document.execCommand("copy")) {
      throw new Error("execCommand copy returned false");
    }
  } finally {
    document.body.removeChild(textarea);
  }
}

function ShareBar01Inner(props: ShareBar01Props) {
  const {
    targets,
    url,
    title,
    text,
    via,
    hashtags,
    onShare,
    onCopySuccess,
    onCopyError,
    successResetMs = 2000,
    divider = false,
    headingAs,
    labels,
    className,
    headerClassName,
    buttonClassName,
  } = props;

  const HeadingTag = headingAs;
  const resolvedLabels = { ...SHARE_BAR_DEFAULT_LABELS, ...labels };
  const headingId = useId();

  const [copyState, setCopyState] = useState<CopyState>("idle");
  const resetTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(
    () => () => {
      if (resetTimer.current !== null) {
        clearTimeout(resetTimer.current);
      }
    },
    []
  );

  const scheduleReset = useCallback((ms: number) => {
    if (resetTimer.current !== null) {
      clearTimeout(resetTimer.current);
    }
    resetTimer.current = setTimeout(() => setCopyState("idle"), ms);
  }, []);

  const resolveUrl = useCallback(() => {
    if (url) return url;
    return typeof window !== "undefined" ? window.location.href : "";
  }, [url]);

  const handleClick = useCallback(
    (target: ShareTarget) => async () => {
      if (target.kind === "copy") {
        try {
          await copyToClipboard(resolveUrl());
          setCopyState("success");
          onCopySuccess?.();
          onShare?.("copy");
          scheduleReset(successResetMs);
        } catch (err) {
          setCopyState("error");
          onCopyError?.(err);
          scheduleReset(successResetMs);
        }
        return;
      }

      if (target.kind === "custom") {
        target.onClick();
        onShare?.(target.id);
        return;
      }

      const shareUrl = SHARE_TEMPLATES[target.kind]({
        url: resolveUrl(),
        title,
        text,
        via,
        hashtags,
      });
      if (typeof window !== "undefined") {
        window.open(shareUrl, "_blank", "noopener,noreferrer");
      }
      onShare?.(target.kind);
    },
    [
      resolveUrl,
      title,
      text,
      via,
      hashtags,
      onShare,
      onCopySuccess,
      onCopyError,
      successResetMs,
      scheduleReset,
    ]
  );

  return (
    <div
      className={cn(divider && "pt-8 border-t border-border", className)}
      aria-labelledby={HeadingTag ? headingId : undefined}
    >
      {HeadingTag ? (
        <HeadingTag
          id={headingId}
          className={cn(
            "text-sm font-semibold text-muted-foreground mb-3",
            headerClassName
          )}
        >
          {resolvedLabels.heading}
        </HeadingTag>
      ) : null}

      <ul role="list" className="flex flex-wrap items-center gap-2 list-none">
        {targets.map((target) => {
          const key = target.kind === "custom" ? target.id : target.kind;
          return (
            <ShareButton
              key={key}
              target={target}
              state={target.kind === "copy" ? copyState : "idle"}
              onClick={handleClick(target)}
              buttonClassName={buttonClassName}
              copyAriaLabel={resolvedLabels.copyAria}
            />
          );
        })}
      </ul>

      <span className="sr-only" role="status" aria-live="polite">
        {copyState === "success" ? resolvedLabels.copySuccess : ""}
      </span>
      <span className="sr-only" role="alert">
        {copyState === "error" ? resolvedLabels.copyError : ""}
      </span>
    </div>
  );
}

export const ShareBar01 = memo(ShareBar01Inner);
ShareBar01.displayName = "ShareBar01";

export { ShareBar01 } from "./share-bar-01";
export {
  SHARE_BAR_DEFAULT_LABELS,
  type ShareBar01Labels,
  type ShareBar01Props,
  type ShareKind,
  type ShareTarget,
  type ShareTargetBuiltin,
  type ShareTargetCopy,
  type ShareTargetCustom,
} from "./types";
export { SHARE_TEMPLATES } from "./parts/templates";
export { meta } from "./meta";

import type { ComponentType } from "react";

export type ShareKind =
  | "twitter"
  | "facebook"
  | "linkedin"
  | "reddit"
  | "whatsapp"
  | "telegram"
  | "email"
  | "threads"
  | "bluesky";

export interface ShareTargetBuiltin {
  kind: ShareKind;
  icon?: ComponentType<{ className?: string }>;
  ariaLabel?: string;
}

export interface ShareTargetCopy {
  kind: "copy";
  icon?: ComponentType<{ className?: string }>;
  ariaLabel?: string;
}

export interface ShareTargetCustom {
  kind: "custom";
  id: string;
  icon: ComponentType<{ className?: string }>;
  ariaLabel: string;
  onClick: () => void;
}

export type ShareTarget = ShareTargetBuiltin | ShareTargetCopy | ShareTargetCustom;

export interface ShareBar01Labels {
  heading?: string;
  copyAria?: string;
  copySuccess?: string;
  copyError?: string;
}

export interface ShareBar01Props {
  targets: ReadonlyArray<ShareTarget>;
  url?: string;
  title?: string;
  text?: string;
  via?: string;
  hashtags?: ReadonlyArray<string>;
  onShare?: (targetKind: string) => void;
  onCopySuccess?: () => void;
  onCopyError?: (err: unknown) => void;
  successResetMs?: number;
  divider?: boolean;
  headingAs?: "h2" | "h3" | "h4" | null;
  labels?: ShareBar01Labels;
  className?: string;
  headerClassName?: string;
  buttonClassName?: string;
}

export const SHARE_BAR_DEFAULT_LABELS: Required<ShareBar01Labels> = {
  heading: "Share",
  copyAria: "Copy link",
  copySuccess: "Link copied",
  copyError: "Couldn't copy link",
};

import { Check, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { DEFAULT_ARIA, DEFAULT_ICONS } from "./icons";
import type { ShareTarget } from "../types";

export type CopyState = "idle" | "success" | "error";

interface ShareButtonProps {
  target: ShareTarget;
  state: CopyState;
  onClick: () => void;
  buttonClassName?: string;
  copyAriaLabel?: string;
}

export function ShareButton({
  target,
  state,
  onClick,
  buttonClassName,
  copyAriaLabel,
}: ShareButtonProps) {
  const isCopy = target.kind === "copy";
  const isCustom = target.kind === "custom";

  const Icon =
    isCopy && state === "success"
      ? Check
      : isCopy && state === "error"
        ? X
        : target.icon ??
          (isCustom ? null : DEFAULT_ICONS[target.kind]);

  const ariaLabel = isCustom
    ? target.ariaLabel
    : isCopy
      ? target.ariaLabel ?? copyAriaLabel ?? DEFAULT_ARIA.copy
      : target.ariaLabel ?? DEFAULT_ARIA[target.kind];

  return (
    <li>
      <Button
        type="button"
        variant="outline"
        size="icon"
        className={cn(
          "rounded-full",
          isCopy && state === "success" && "text-primary",
          isCopy && state === "error" && "text-destructive",
          buttonClassName
        )}
        title={ariaLabel}
        aria-label={ariaLabel}
        onClick={onClick}
      >
        {Icon ? <Icon className="w-4 h-4" /> : null}
      </Button>
    </li>
  );
}

import type { ShareKind } from "../types";

export interface ShareUrlContext {
  url: string;
  title?: string;
  text?: string;
  via?: string;
  hashtags?: ReadonlyArray<string>;
}

type Builder = (ctx: ShareUrlContext) => string;

const enc = encodeURIComponent;

export const SHARE_TEMPLATES: Record<ShareKind, Builder> = {
  twitter: ({ url, title, via, hashtags }) => {
    const params = new URLSearchParams({ url });
    if (title) params.set("text", title);
    if (via) params.set("via", via);
    if (hashtags && hashtags.length > 0) {
      params.set("hashtags", hashtags.join(","));
    }
    return `https://twitter.com/intent/tweet?${params.toString()}`;
  },
  facebook: ({ url }) =>
    `https://www.facebook.com/sharer/sharer.php?u=${enc(url)}`,
  linkedin: ({ url }) =>
    `https://www.linkedin.com/sharing/share-offsite/?url=${enc(url)}`,
  reddit: ({ url, title }) => {
    const params = new URLSearchParams({ url });
    if (title) params.set("title", title);
    return `https://reddit.com/submit?${params.toString()}`;
  },
  whatsapp: ({ url, title }) => {
    const text = [title, url].filter(Boolean).join(" ");
    return `https://wa.me/?text=${enc(text)}`;
  },
  telegram: ({ url, title }) => {
    const params = new URLSearchParams({ url });
    if (title) params.set("text", title);
    return `https://t.me/share/url?${params.toString()}`;
  },
  email: ({ url, title, text }) => {
    const params = new URLSearchParams();
    if (title) params.set("subject", title);
    params.set("body", [text, url].filter(Boolean).join("\n\n"));
    return `mailto:?${params.toString()}`;
  },
  threads: ({ url, title }) => {
    const text = [title, url].filter(Boolean).join(" ");
    return `https://www.threads.net/intent/post?text=${enc(text)}`;
  },
  bluesky: ({ url, title }) => {
    const text = [title, url].filter(Boolean).join(" ");
    return `https://bsky.app/intent/compose?text=${enc(text)}`;
  },
};

import { Copy, Mail, MessageCircle, Send } from "lucide-react";
import type { ComponentType } from "react";
import {
  Bluesky,
  Facebook,
  LinkedIn,
  Reddit,
  Threads,
  TwitterX,
} from "./brand-icons";
import type { ShareKind } from "../types";

export const DEFAULT_ICONS: Record<
  ShareKind | "copy",
  ComponentType<{ className?: string }>
> = {
  twitter: TwitterX,
  facebook: Facebook,
  linkedin: LinkedIn,
  reddit: Reddit,
  whatsapp: MessageCircle,
  telegram: Send,
  email: Mail,
  threads: Threads,
  bluesky: Bluesky,
  copy: Copy,
};

export const DEFAULT_ARIA: Record<ShareKind | "copy", string> = {
  twitter: "Share on X",
  facebook: "Share on Facebook",
  linkedin: "Share on LinkedIn",
  reddit: "Share on Reddit",
  whatsapp: "Share on WhatsApp",
  telegram: "Share on Telegram",
  email: "Share via email",
  threads: "Share on Threads",
  bluesky: "Share on Bluesky",
  copy: "Copy link",
};
